#include <string.h>
#include <arpa/inet.h>
#include <netinet/in.h>

// ★ Stage 0 — Exemple complet
typedef struct {
    struct sockaddr_in src;     // ★ adresse source
    struct sockaddr_in dst;     // ★ adresse destination
    char payload[64];           // ★ données transportées
} NetMsg;

int main(void) {
    NetMsg msg;
    memset(&msg, 0, sizeof(msg));              // ★ TOUJOURS zéro-init (sin_zero[] garbage sinon)
    msg.src.sin_family = AF_INET;
    msg.src.sin_port = htons(1234);            // ★ port source → big-endian
    inet_pton(AF_INET, "10.0.0.1", &msg.src.sin_addr); // ★ IP string → binaire
    msg.dst.sin_family = AF_INET;
    msg.dst.sin_port = htons(5678);            // ★ port destination → big-endian
    inet_pton(AF_INET, "10.0.0.2", &msg.dst.sin_addr);
    strncpy(msg.payload, "ping", sizeof(msg.payload) - 1); // ★ copie sécurisée
    char src_ip[INET_ADDRSTRLEN], dst_ip[INET_ADDRSTRLEN];
    inet_ntop(AF_INET, &msg.src.sin_addr, src_ip, sizeof(src_ip));
    inet_ntop(AF_INET, &msg.dst.sin_addr, dst_ip, sizeof(dst_ip));
    printf("From: %s:%d -> To: %s:%d\n",
           src_ip, ntohs(msg.src.sin_port),   // ★ ntohs pour afficher
           dst_ip, ntohs(msg.dst.sin_port));
    printf("Payload: %s\n", msg.payload);
    return 0;
}

